import { H4 } from "../../../AbstractElements";

export const addonColumns = (ActionCell, authState) => [
    {
        name: <i className="fa fa-gears" style={{ fontSize: '15px' }}></i>,
        selector: row => row.action,
        cell: row => <ActionCell row={row} />,
        sortable: true,
        center: true,
        width: '60px',
    },
    {
        name: <H4>Image</H4>,
        selector: row => <span style={{ width: "20px", height: "20px" }}>{row.Image}</span>,
        sortable: true,
        width: '80px'
    },
    {
        name: <H4>Name</H4>,
        selector: row => row.Name,
        sortable: true,
        wrap: true,
        width: '130px',
        sortFunction: (a, b) => {
            const nameA = a?.Name?.toString().toLowerCase() || '';
            const nameB = b?.Name?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Category name</H4>,
        selector: row => row.category_type,
        sortable: true,
        wrap: true,
        width: '100px',
        sortFunction: (a, b) => {
            const nameA = a?.category_type?.toString().toLowerCase() || '';
            const nameB = b?.category_type?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Tax %</H4>,
        selector: row => parseFloat(row.Tax.replace('%', '').trim()),
        cell: row => row.Tax,
        sortable: true,
        center: true,
        wrap: true,
        width: '70px'
    },
    {
        name: <H4>Bill Cycle</H4>,
        selector: row => row.bill_type,
        sortable: true,
        center: false,
        width: '120px',

        sortFunction: (a, b) => {
            const nameA = a?.bill_type?.toString().toLowerCase() || '';
            const nameB = b?.bill_type?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Duration Days</H4>,
        selector: row => row.Duration,
        sortable: true,
        width: '100px'
    },
    {
        name: <H4>Price</H4>,
        selector: row => parseFloat(
            row.Price
                .replace(authState.currency, '')
                .replace(/,/g, '')
                .trim()
        ),
        cell: row => row.Price,
        sortable: true,
        center: true,
        width: '150px'
    },
    {
        name: <H4>Total</H4>,
        selector: row => parseFloat(
            row.Total
                .replace(authState.currency, '')
                .replace(/,/g, '')
                .trim()
        ),
        cell: row => row.Total,
        sortable: true,
        center: true,
        width: '150px'
    },
    {
        name: <H4>Description</H4>,
        selector: row => row.Description,
        sortable: true,
        wrap: true,
        width: '190px',
        sortFunction: (a, b) => {
            const nameA = a?.Description?.toString().toLowerCase() || '';
            const nameB = b?.Description?.toString().toLowerCase() || '';
            if (nameA < nameB) return -1;
            if (nameA > nameB) return 1;
            return 0;
        }
    },
    {
        name: <H4>Status</H4>,
        selector: row => row.Status,
        sortable: true,
    },
];

